const skillsData = $('Top Skills').first().json;
const trendsData = $('Trends').first().json;
const profilesData = $('Profiles').first().json;

const skills = skillsData.skills || [];
const trends = trendsData.trends || {};
const profiles = profilesData.profiles || {};

const top10 = skills.slice(0, 10);
const rising = (trends.RISING || []).slice(0, 5);
const falling = (trends.FALLING || []).slice(0, 5);

const lines = [];
lines.push('📊 Еженедельный отчёт по рынку');
lines.push('');
lines.push('🏆 Топ-10 навыков:');
top10.forEach((s, i) => lines.push(`  ${i+1}. ${s.skill} (${s.weight})`));
lines.push('');
if (rising.length) {
  lines.push('📈 Растущие тренды:');
  rising.forEach(s => lines.push(`  ${s.skill} +${s.change_pct}%`));
}
if (falling.length) {
  lines.push('📉 Падающие тренды:');
  falling.forEach(s => lines.push(`  ${s.skill} ${s.change_pct}%`));
}
lines.push('');
lines.push('👤 Оценка профилей:');
for (const [name, p] of Object.entries(profiles)) {
  const r = p.readiness_score != null ? p.readiness_score.toFixed(0) : '—';
  const c = p.market_coverage_score != null ? p.market_coverage_score.toFixed(0) : '—';
  lines.push(`  ${name}: готовность ${r}%, покрытие ${c}%`);
}

let html = `<h2>Еженедельный отчёт по рынку</h2>`;
html += `<h3>🏆 Топ-10 навыков</h3><table border=1 cellpadding=4><tr><th>#</th><th>Навык</th><th>Вес</th></tr>`;
top10.forEach((s, i) => { html += `<tr><td>${i+1}</td><td>${s.skill}</td><td>${s.weight}</td></tr>`; });
html += `</table>`;
if (rising.length) {
  html += `<h3>📈 Растущие тренды</h3><table border=1 cellpadding=4><tr><th>Навык</th><th>Изменение</th></tr>`;
  rising.forEach(s => { html += `<tr><td>${s.skill}</td><td style="color:green">+${s.change_pct}%</td></tr>`; });
  html += `</table>`;
}
if (falling.length) {
  html += `<h3>📉 Падающие тренды</h3><table border=1 cellpadding=4><tr><th>Навык</th><th>Изменение</th></tr>`;
  falling.forEach(s => { html += `<tr><td>${s.skill}</td><td style="color:red">${s.change_pct}%</td></tr>`; });
  html += `</table>`;
}
html += `<h3>👤 Профили</h3><table border=1 cellpadding=4><tr><th>Профиль</th><th>Готовность</th><th>Покрытие</th></tr>`;
for (const [name, p] of Object.entries(profiles)) {
  const r = p.readiness_score != null ? p.readiness_score.toFixed(0) : '—';
  const c = p.market_coverage_score != null ? p.market_coverage_score.toFixed(0) : '—';
  html += `<tr><td>${name}</td><td>${r}%</td><td>${c}%</td></tr>`;
}
html += `</table>`;

return [{ json: { summary: lines.join('\n'), html: html } }];
